diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..606c48268dea 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3345,6 +3345,30 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         return new ICmpInst(Pred, BOp0, Neg);
       }
     }
+    Value *A, *B;
+    if (match(BOp0, m_ZExt(m_Value(A))) && match(BOp1, m_ZExt(m_Value(B))) &&
+        A->getType()->isIntOrIntVectorTy(1) && B->getType()->isIntOrIntVectorTy(1)) {
+      if (C == 1)
+        return new ICmpInst(isICMP_NE ? ICmpInst::ICMP_EQ : ICmpInst::ICMP_NE, A, B);
+      if (C == 0)
+        return new ICmpInst(Pred, Builder.CreateOr(A, B), ConstantInt::getNullValue(A->getType()));
+      if (C == 2)
+        return new ICmpInst(Pred, Builder.CreateAnd(A, B), ConstantInt::getAllOnesValue(A->getType()));
+    }
+    if (match(BOp0, m_SExt(m_Value(A))) && match(BOp1, m_SExt(m_Value(B))) &&
+        A->getType()->isIntOrIntVectorTy(1) && B->getType()->isIntOrIntVectorTy(1)) {
+      if (C == -1)
+        return new ICmpInst(isICMP_NE ? ICmpInst::ICMP_EQ : ICmpInst::ICMP_NE, A, B);
+    }
+    if (match(BOp0, m_SExt(m_Value(A))) && match(BOp1, m_SExt(m_Value(B))) &&
+        A->getType()->isIntOrIntVectorTy(1) && B->getType()->isIntOrIntVectorTy(1)) {
+      if (C == -1)
+        return new ICmpInst(isICMP_NE ? ICmpInst::ICMP_EQ : ICmpInst::ICMP_NE, A, B);
+      if (C == 0)
+        return new ICmpInst(Pred, Builder.CreateOr(A, B), ConstantInt::getNullValue(A->getType()));
+      if (C == -2)
+        return new ICmpInst(Pred, Builder.CreateAnd(A, B), ConstantInt::getAllOnesValue(A->getType()));
+    }
     break;
   }
   case Instruction::Xor:

